(() => {
  const ctx = document.getElementById('passChart').getContext('2d');

  // Average Pass@1 across 5 languages from Table 4
  const models = ['DeepSeek-R1', 'GPT-4.1', 'Claude 3.7', 'DeepSeek-V3', 'Qwen2.5-Coder', 'Llama-3.3'];
  const avgPass = [
    ((89.30 + 87.82 + 87.92 + 86.97 + 87.71) / 5),
    ((86.55 + 85.91 + 86.12 + 83.26 + 84.43) / 5),
    ((85.06 + 82.31 + 83.79 + 81.36 + 82.84) / 5),
    ((85.49 + 84.96 + 84.96 + 80.08 + 84.00) / 5),
    ((74.58 + 72.35 + 71.82 + 70.13 + 70.44) / 5),
    ((54.77 + 53.07 + 51.80 + 52.75 + 51.38) / 5)
  ];

  const colors = ['#4dabf7', '#4dabf7', '#4dabf7', '#4dabf7', '#f6ad55', '#ff6b6b'];

  new Chart(ctx, {
    type: 'bar',
    data: {
      labels: models,
      datasets: [{
        label: 'Avg Pass@1 (%)',
        data: avgPass.map(v => Math.round(v * 10) / 10),
        backgroundColor: colors,
        borderRadius: 6,
        maxBarThickness: 64
      }]
    },
    options: {
      animation: false,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: {
            label: (c) => c.parsed.y.toFixed(1) + '%'
          }
        }
      },
      scales: {
        y: {
          beginAtZero: false,
          min: 40,
          max: 95,
          ticks: {
            callback: (v) => v + '%',
            font: { size: 12 }
          },
          grid: { color: '#e2e8f0' }
        },
        x: {
          ticks: { font: { size: 11.5 } },
          grid: { display: false }
        }
      }
    }
  });
})();
